package kotlinx.datetime.test.format

import kotlinx.datetime.DateTimeFormatException
import kotlinx.datetime.LocalDate
import kotlinx.datetime.LocalTime
import kotlinx.datetime.format.DateTimeFormat
import kotlinx.datetime.format.char
import kotlinx.datetime.format.hour
import kotlinx.datetime.format.minute
import kotlinx.datetime.format.amPmMarker
import kotlinx.datetime.format.amPmHour
import kotlinx.datetime.format.FormatStringsInDatetimeFormats
import kotlin.test.Test
import kotlin.test.assertContains
import kotlin.test.assertFailsWith

class ParsingErrorMessageTest {

    @Test
    fun testValidationErrorsIncludeFullInput() {
        val format: DateTimeFormat<LocalTime> = LocalTime.Format {
            hour()
            char(':')
            minute()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val input = "23:00 AM"
        val error = assertFailsWith<DateTimeFormatException> { format.parse(input) }
        assertContains(error.message!!, "Failed to parse value from '$input'")
        assertContains(error.message!!, "Inconsistent hour and the AM/PM marker")
    }

    @Test
    fun testConstructorValidationErrorsIncludeFullInput() {
        val input = "2023-02-40"
        val error = assertFailsWith<DateTimeFormatException> { LocalDate.Formats.ISO.parse(input) }
        assertContains(error.message!!, "Failed to parse value from '$input'")
        assertContains(error.message!!, "40")
    }

    @Test
    fun testExpectedOneOfIsLowercased() {
        val format: DateTimeFormat<LocalTime> = LocalTime.Format {
            amPmHour()
            char(':')
            minute()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val error = assertFailsWith<DateTimeFormatException> { format.parse("01:02 XX") }
        val causeMessage = error.cause?.message
        assertContains(causeMessage ?: "", "Expected one of")
    }
}
"}

